const UserManagementPage=()=>{
  const[accounts,setAccounts]=useState(INIT_PIU_ACCOUNTS);
  const[logs]=useState(INIT_LOGS);
  const[expandedPiu,setExpandedPiu]=useState(null);
  const[showCreateModal,setShowCreateModal]=useState(false);
  const[showEditModal,setShowEditModal]=useState(null);
  const[logFilter,setLogFilter]=useState("all");
  const[tab,setTab]=useState("accounts");

  const toggleStatus=(id)=>{setAccounts(prev=>prev.map(a=>a.id===id?{...a,status:a.status==="Active"?"Deactivated":"Active"}:a))};

  const filteredLogs=logFilter==="all"?logs:logs.filter(l=>l.type===logFilter);

  return (<div>
    <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:20}}>
      <div><div style={{fontSize:20,fontWeight:700}}>User Management</div><div style={{fontSize:12,color:"#94A3B8"}}>Manage PIU accounts, team members, and view activity logs</div></div>
      <button onClick={()=>setShowCreateModal(true)} style={{...S.filterBtn,padding:"10px 20px",fontSize:13}}>+ Create PIU Account</button>
    </div>

    {/* Stats */}
    <div style={{display:"grid",gridTemplateColumns:"repeat(4,1fr)",gap:16,marginBottom:24}}>
      {[{l:"Total PIUs",v:accounts.length,bg:"#DBEAFE",i:<LayoutDashboard size={18} color="#3B82F6"/>},{l:"Active",v:accounts.filter(a=>a.status==="Active").length,bg:"#DCFCE7",i:<CheckCircle2 size={18} color="#16A34A"/>},{l:"Deactivated",v:accounts.filter(a=>a.status==="Deactivated").length,bg:"#FEE2E2",i:<X size={18} color="#DC2626"/>},{l:"Total Members",v:accounts.reduce((s,a)=>s+a.members.length,0),bg:"#FEF3C7",i:<Users size={18} color="#D97706"/>}].map((k,i)=>(
        <div key={i} style={S.kpi}><div style={{display:"flex",justifyContent:"space-between"}}><div><div style={S.kpiLabel}>{k.l}</div><div style={S.kpiValue}>{k.v}</div></div><div style={S.kpiIcon(k.bg)}>{k.i}</div></div></div>
      ))}
    </div>

    {/* Tabs */}
    <div style={{display:"flex",gap:4,marginBottom:20}}>
      {[{id:"accounts",label:"PIU Accounts"},{id:"logs",label:"Activity Log"}].map(t=>(
        <button key={t.id} onClick={()=>setTab(t.id)} style={{padding:"8px 20px",borderRadius:"8px 8px 0 0",border:"1px solid #E2E8F0",borderBottom:tab===t.id?"2px solid #0E7490":"1px solid #E2E8F0",background:tab===t.id?"#fff":"#F8FAFC",color:tab===t.id?"#0E7490":"#64748B",fontWeight:tab===t.id?700:400,fontSize:13,cursor:"pointer"}}>{t.label}</button>
      ))}
    </div>

    {tab==="accounts"&&<div>
      {accounts.map(piu=>(
        <div key={piu.id} style={{...S.card,border:expandedPiu===piu.id?"1px solid #0E7490":"1px solid transparent"}}>
          {/* PIU header row */}
          <div style={{display:"flex",justifyContent:"space-between",alignItems:"center"}}>
            <div style={{display:"flex",alignItems:"center",gap:14}}>
              <div style={{...S.avatar,width:44,height:44,fontSize:16,background:piu.status==="Active"?"#0E7490":"#94A3B8"}}>{piu.name.charAt(4)}</div>
              <div>
                <div style={{display:"flex",alignItems:"center",gap:8}}><span style={{fontWeight:700,fontSize:14}}>{piu.name}</span><span style={S.badge(piu.status==="Active"?"Ongoing":"Halted")}>{piu.status}</span></div>
                <div style={{fontSize:11,color:"#64748B",marginTop:2}}>Head: {piu.head} • {piu.email}</div>
                <div style={{fontSize:10,color:"#94A3B8"}}>Created: {piu.created} • Last login: {piu.lastLogin} • {piu.projects} projects • {piu.members.length} members</div>
              </div>
            </div>
            <div style={{display:"flex",gap:8,alignItems:"center"}}>
              <button onClick={()=>setShowEditModal(piu)} style={{padding:"6px 14px",borderRadius:6,border:"1px solid #E2E8F0",background:"#fff",fontSize:11,cursor:"pointer",fontWeight:600,color:"#475569"}}>✏️ Edit</button>
              <button onClick={()=>toggleStatus(piu.id)} style={{padding:"6px 14px",borderRadius:6,border:"none",background:piu.status==="Active"?"#FEE2E2":"#DCFCE7",fontSize:11,cursor:"pointer",fontWeight:600,color:piu.status==="Active"?"#DC2626":"#16A34A"}}>{piu.status==="Active"?<><X size={12}/> Deactivate</>:<><CheckCircle2 size={12}/> Activate</>}</button>
              <button onClick={()=>setExpandedPiu(expandedPiu===piu.id?null:piu.id)} style={{padding:"6px 14px",borderRadius:6,border:"1px solid #E2E8F0",background:"#F8FAFC",fontSize:11,cursor:"pointer",fontWeight:600,color:"#0E7490"}}>{expandedPiu===piu.id?"▲ Hide Members":"▼ View Members ("+piu.members.length+")"}</button>
            </div>
          </div>

          {/* Expanded members */}
          {expandedPiu===piu.id&&<div style={{marginTop:16,paddingTop:16,borderTop:"1px solid #F1F5F9"}}>
            <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:12}}>
              <div style={{fontSize:13,fontWeight:700,color:"#1E293B"}}>Team Members — {piu.name}</div>
            </div>
            <table style={S.table}>
              <thead><tr>{["Name","Role","Email","Phone","Status","Last Active"].map(h=><th key={h} style={S.th}>{h}</th>)}</tr></thead>
              <tbody>{piu.members.map(m=>(
                <tr key={m.id}>
                  <td style={{...S.td,fontWeight:600}}><div style={{display:"flex",alignItems:"center",gap:8}}><div style={{width:28,height:28,borderRadius:"50%",background:m.status==="Active"?"#DBEAFE":"#F1F5F9",display:"flex",alignItems:"center",justifyContent:"center",fontSize:11,fontWeight:700,color:m.status==="Active"?"#2563EB":"#94A3B8"}}>{m.name.charAt(0)}</div>{m.name}</div></td>
                  <td style={S.td}><span style={{...S.badge(m.role==="PIU Head"?"Execution":"Design"),fontSize:10}}>{m.role}</span></td>
                  <td style={{...S.td,fontSize:11}}>{m.email}</td>
                  <td style={{...S.td,fontSize:11}}>{m.phone}</td>
                  <td style={S.td}><span style={{display:"flex",alignItems:"center",gap:4,fontSize:11}}><span style={{width:6,height:6,borderRadius:"50%",background:m.status==="Active"?"#16A34A":"#94A3B8"}}/>{m.status}</span></td>
                  <td style={{...S.td,fontSize:11,color:"#64748B"}}>{m.lastActive}</td>
                </tr>
              ))}</tbody>
            </table>
          </div>}
        </div>
      ))}
    </div>}

    {tab==="logs"&&<div style={S.card}>
      <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:16}}>
        <div style={S.cardTitle}>Activity Log</div>
        <div style={{display:"flex",gap:6}}>
          {[{id:"all",label:"All"},{id:"account",label:"Account"},{id:"member",label:"Member"}].map(f=>(
            <button key={f.id} onClick={()=>setLogFilter(f.id)} style={{padding:"4px 14px",borderRadius:16,border:logFilter===f.id?"2px solid #0E7490":"1px solid #E2E8F0",background:logFilter===f.id?"#E0F2FE":"#fff",color:logFilter===f.id?"#0E7490":"#64748B",fontSize:11,fontWeight:600,cursor:"pointer"}}>{f.label}</button>
          ))}
        </div>
      </div>
      <table style={S.table}>
        <thead><tr>{["Timestamp","User","Action","Target","Type"].map(h=><th key={h} style={S.th}>{h}</th>)}</tr></thead>
        <tbody>{filteredLogs.map(l=>(
          <tr key={l.id}>
            <td style={{...S.td,fontSize:11,color:"#64748B",whiteSpace:"nowrap"}}>{l.time}</td>
            <td style={{...S.td,fontWeight:600}}><span style={S.badge(l.user==="Gov-Admin"?"Completed":"In Progress")}>{l.user}</span></td>
            <td style={{...S.td,fontWeight:500}}>{l.action}</td>
            <td style={{...S.td,fontSize:11}}>{l.target}</td>
            <td style={S.td}><span style={{...S.badge(l.type==="account"?"Design":"Medium"),fontSize:10,textTransform:"capitalize"}}>{l.type}</span></td>
          </tr>
        ))}</tbody>
      </table>
    </div>}

    {/* Create Modal */}
    {showCreateModal&&<div style={{position:"fixed",inset:0,background:"rgba(0,0,0,0.4)",display:"flex",alignItems:"center",justifyContent:"center",zIndex:2000}} onClick={()=>setShowCreateModal(false)}>
      <div onClick={e=>e.stopPropagation()} style={{background:"#fff",borderRadius:16,padding:28,width:420,boxShadow:"0 20px 60px rgba(0,0,0,0.2)"}}>
        <div style={{fontSize:18,fontWeight:700,marginBottom:4}}>Create New PIU Account</div>
        <div style={{fontSize:12,color:"#94A3B8",marginBottom:20}}>Fill in the details to create a new PIU user account</div>
        {[{l:"PIU Name",p:"e.g., PIU Chamoli"},{l:"Head of PIU",p:"Full name"},{l:"Email Address",p:"official@utdb.gov.in"},{l:"Phone Number",p:"+91 XXXXX XXXXX"},{l:"Username",p:"piu-chamoli"},{l:"Temporary Password",p:"Min 8 characters"}].map(f=>(
          <div key={f.l} style={{marginBottom:12}}><div style={{fontSize:11,fontWeight:600,color:"#475569",marginBottom:4}}>{f.l}</div><input placeholder={f.p} style={{...S.loginInput,marginBottom:0}}/></div>
        ))}
        <div style={{display:"flex",gap:10,marginTop:20}}>
          <button onClick={()=>setShowCreateModal(false)} style={{flex:1,padding:"10px 0",borderRadius:8,border:"1px solid #E2E8F0",background:"#fff",cursor:"pointer",fontWeight:600,fontSize:13}}>Cancel</button>
          <button onClick={()=>setShowCreateModal(false)} style={{flex:1,padding:"10px 0",borderRadius:8,border:"none",background:"#0E7490",color:"#fff",cursor:"pointer",fontWeight:600,fontSize:13}}>Create Account</button>
        </div>
      </div>
    </div>}

    {/* Edit Modal */}
    {showEditModal&&<div style={{position:"fixed",inset:0,background:"rgba(0,0,0,0.4)",display:"flex",alignItems:"center",justifyContent:"center",zIndex:2000}} onClick={()=>setShowEditModal(null)}>
      <div onClick={e=>e.stopPropagation()} style={{background:"#fff",borderRadius:16,padding:28,width:420,boxShadow:"0 20px 60px rgba(0,0,0,0.2)"}}>
        <div style={{fontSize:18,fontWeight:700,marginBottom:4}}>Edit PIU Account</div>
        <div style={{fontSize:12,color:"#94A3B8",marginBottom:20}}>{showEditModal.name}</div>
        {[{l:"PIU Name",v:showEditModal.name},{l:"Head of PIU",v:showEditModal.head},{l:"Email Address",v:showEditModal.email},{l:"Phone Number",v:showEditModal.phone}].map(f=>(
          <div key={f.l} style={{marginBottom:12}}><div style={{fontSize:11,fontWeight:600,color:"#475569",marginBottom:4}}>{f.l}</div><input defaultValue={f.v} style={{...S.loginInput,marginBottom:0}}/></div>
        ))}
        <div style={{display:"flex",gap:10,marginTop:20}}>
          <button onClick={()=>setShowEditModal(null)} style={{flex:1,padding:"10px 0",borderRadius:8,border:"1px solid #E2E8F0",background:"#fff",cursor:"pointer",fontWeight:600,fontSize:13}}>Cancel</button>
          <button onClick={()=>setShowEditModal(null)} style={{flex:1,padding:"10px 0",borderRadius:8,border:"none",background:"#0E7490",color:"#fff",cursor:"pointer",fontWeight:600,fontSize:13}}>Save Changes</button>
        </div>
      </div>
    </div>}
  </div>);
};

const TeamPage=({piuUser:pu})=>{
  const piuAccount=INIT_PIU_ACCOUNTS.find(a=>a.id===pu)||INIT_PIU_ACCOUNTS[0];
  const[members,setMembers]=useState(piuAccount.members);
  const[showAdd,setShowAdd]=useState(false);
  const[logs]=useState(INIT_LOGS.filter(l=>l.user===piuAccount.name||l.target?.includes(piuAccount.name.split(" ")[1])));

  return (<div>
    <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:20}}>
      <div><div style={{fontSize:20,fontWeight:700}}>My Team — {piuAccount.name}</div><div style={{fontSize:12,color:"#94A3B8"}}>Manage your PIU team members</div></div>
      <button onClick={()=>setShowAdd(true)} style={{...S.filterBtn,padding:"10px 20px",fontSize:13}}>+ Add Team Member</button>
    </div>

    <div style={{display:"grid",gridTemplateColumns:"repeat(3,1fr)",gap:16,marginBottom:24}}>
      {[{l:"Total Members",v:members.length,bg:"#DBEAFE",i:<Users size={18} color="#D97706"/>},{l:"Active",v:members.filter(m=>m.status==="Active").length,bg:"#DCFCE7",i:<CheckCircle2 size={18} color="#16A34A"/>},{l:"Inactive",v:members.filter(m=>m.status==="Inactive").length,bg:"#FEE2E2",i:<X size={18} color="#DC2626"/>}].map((k,i)=>(
        <div key={i} style={S.kpi}><div style={{display:"flex",justifyContent:"space-between"}}><div><div style={S.kpiLabel}>{k.l}</div><div style={{fontSize:28,fontWeight:700,color:"#1E293B"}}>{k.v}</div></div><div style={S.kpiIcon(k.bg)}>{k.i}</div></div></div>
      ))}
    </div>

    {/* Members grid */}
    <div style={{display:"grid",gridTemplateColumns:"repeat(2,1fr)",gap:16,marginBottom:24}}>
      {members.map(m=>(
        <div key={m.id} style={{...S.card,marginBottom:0,border:m.status==="Active"?"1px solid #E2E8F0":"1px solid #FEE2E2"}}>
          <div style={{display:"flex",justifyContent:"space-between",alignItems:"flex-start"}}>
            <div style={{display:"flex",gap:12,alignItems:"center"}}>
              <div style={{width:44,height:44,borderRadius:"50%",background:m.status==="Active"?"linear-gradient(135deg,#0E7490,#14B8A6)":"#E2E8F0",display:"flex",alignItems:"center",justifyContent:"center",color:m.status==="Active"?"#fff":"#94A3B8",fontWeight:700,fontSize:16}}>{m.name.charAt(0)}</div>
              <div>
                <div style={{fontWeight:700,fontSize:14}}>{m.name}</div>
                <div style={{fontSize:11,color:"#64748B"}}>{m.role}</div>
                <div style={{display:"flex",alignItems:"center",gap:4,fontSize:10,color:m.status==="Active"?"#16A34A":"#94A3B8",marginTop:2}}><span style={{width:6,height:6,borderRadius:"50%",background:m.status==="Active"?"#16A34A":"#94A3B8"}}/>{m.status}</div>
              </div>
            </div>
            <button onClick={()=>setMembers(prev=>prev.map(x=>x.id===m.id?{...x,status:x.status==="Active"?"Inactive":"Active"}:x))} style={{padding:"4px 10px",borderRadius:6,border:"1px solid #E2E8F0",background:"#fff",fontSize:10,cursor:"pointer",color:"#64748B"}}>{m.status==="Active"?"Deactivate":"Activate"}</button>
          </div>
          <div style={{marginTop:12,paddingTop:12,borderTop:"1px solid #F1F5F9",display:"grid",gridTemplateColumns:"1fr 1fr",gap:8}}>
            <div><div style={{fontSize:10,color:"#94A3B8"}}>Email</div><div style={{fontSize:11}}>{m.email}</div></div>
            <div><div style={{fontSize:10,color:"#94A3B8"}}>Phone</div><div style={{fontSize:11}}>{m.phone}</div></div>
            <div style={{gridColumn:"span 2"}}><div style={{fontSize:10,color:"#94A3B8"}}>Last Active</div><div style={{fontSize:11}}>{m.lastActive}</div></div>
          </div>
        </div>
      ))}
    </div>

    {/* Activity Log */}
    <div style={S.card}>
      <div style={S.cardTitle}>Recent Activity</div>
      {logs.length===0?<div style={{padding:16,textAlign:"center",color:"#94A3B8",fontSize:12}}>No recent activity</div>:
      <table style={S.table}>
        <thead><tr>{["Time","Action","Details"].map(h=><th key={h} style={S.th}>{h}</th>)}</tr></thead>
        <tbody>{logs.slice(0,5).map(l=>(
          <tr key={l.id}><td style={{...S.td,fontSize:11,color:"#64748B"}}>{l.time}</td><td style={{...S.td,fontWeight:500}}>{l.action}</td><td style={{...S.td,fontSize:11}}>{l.target}</td></tr>
        ))}</tbody>
      </table>}
    </div>

    {/* Add modal */}
    {showAdd&&<div style={{position:"fixed",inset:0,background:"rgba(0,0,0,0.4)",display:"flex",alignItems:"center",justifyContent:"center",zIndex:2000}} onClick={()=>setShowAdd(false)}>
      <div onClick={e=>e.stopPropagation()} style={{background:"#fff",borderRadius:16,padding:28,width:420,boxShadow:"0 20px 60px rgba(0,0,0,0.2)"}}>
        <div style={{fontSize:18,fontWeight:700,marginBottom:4}}>Add Team Member</div>
        <div style={{fontSize:12,color:"#94A3B8",marginBottom:20}}>Add a new member to {piuAccount.name}</div>
        {[{l:"Full Name",p:"Enter full name"},{l:"Role",p:"e.g., Site Engineer"},{l:"Email",p:"email@utdb.gov.in"},{l:"Phone Number",p:"+91 XXXXX XXXXX"}].map(f=>(
          <div key={f.l} style={{marginBottom:12}}><div style={{fontSize:11,fontWeight:600,color:"#475569",marginBottom:4}}>{f.l}</div><input placeholder={f.p} style={{...S.loginInput,marginBottom:0}}/></div>
        ))}
        <div style={{display:"flex",gap:10,marginTop:20}}>
          <button onClick={()=>setShowAdd(false)} style={{flex:1,padding:"10px 0",borderRadius:8,border:"1px solid #E2E8F0",background:"#fff",cursor:"pointer",fontWeight:600,fontSize:13}}>Cancel</button>
          <button onClick={()=>setShowAdd(false)} style={{flex:1,padding:"10px 0",borderRadius:8,border:"none",background:"#0E7490",color:"#fff",cursor:"pointer",fontWeight:600,fontSize:13}}>Add Member</button>
        </div>
      </div>
    </div>}
  </div>);
};

/* ════════════════════════════════════════════════════════
   MAIN APP
   ════════════════════════════════════════════════════════ */
const ADMIN_NAV=[{id:"dashboard",label:"Dashboard",icon:"dashboard"},{id:"pius",label:"PIUs",icon:"piu"},{id:"users",label:"User Management",icon:"piu"},{id:"repo",label:"Repository",icon:"repo"},{id:"grievances",label:"Grievances",icon:"grievance"},{id:"compliance",label:"Compliance",icon:"qc"},{id:"qc",label:"QC & QA Monitoring",icon:"qc"}];
const PIU_NAV=[{id:"dashboard",label:"Dashboard",icon:"dashboard"},{id:"team",label:"My Team",icon:"piu"},{id:"repo",label:"Repository",icon:"repo"},{id:"grievances",label:"Grievances",icon:"grievance"},{id:"qc",label:"QC & QA Monitoring",icon:"qc"}];

export default function App(){
  const[loggedIn,setLoggedIn]=useState(false);const[role,setRole]=useState("admin");const[piuUser,setPiuUser]=useState(null);const[page,setPage]=useState("dashboard");const[selProj,setSelProj]=useState(null);
  if(!loggedIn)return (<LoginPage onLogin={(r,pu)=>{setRole(r);setPiuUser(pu);setLoggedIn(true);setPage("dashboard");setSelProj(null)}}/>);
  const isAdmin=role==="admin";const nav=isAdmin?ADMIN_NAV:PIU_NAV;
  const piuName=piuUser?PIU_USERS[piuUser]:null;const piuProjects=piuName?PROJECTS.filter(p=>p.piu===piuName):[];
  const ddProjects=isAdmin?PROJECTS:piuProjects;

  let dash;
  if(page==="dashboard"){
    if(isAdmin&&selProj===null)dash=<AllProjectsDashboard onSelectProject={id=>setSelProj(id)}/>;
    else{const pid=isAdmin?selProj:(selProj||(piuProjects.length>0?piuProjects[0].id:null));const proj=PROJECTS.find(p=>p.id===pid);dash=proj?<ProjectDashboard project={proj}/>:<div style={{padding:40,textAlign:"center",color:"#94A3B8"}}>No projects assigned.</div>}
  }
  const pages={dashboard:dash,pius:<PIUsPage/>,users:<UserManagementPage/>,team:<TeamPage piuUser={piuUser}/>,repo:<RepoPage/>,grievances:<GrievancesPage/>,compliance:<CompliancePage/>,qc:<QCPage/>};

  return(<div style={S.app}>
    <div style={S.sidebar}>
      <div style={S.sidebarLogo}><Mountain size={32} color="#0E7490"/><p style={{fontSize:14,fontWeight:700,color:"#0E7490",margin:0}}>Uttarakhand</p><p style={{fontSize:10,color:"#0E7490",fontStyle:"italic",margin:0}}>Simply Heaven!</p></div>
      <div style={S.nav}>{nav.map(n=><div key={n.id} style={S.navItem(page===n.id)} onClick={()=>{setPage(n.id);if(n.id==="dashboard"&&isAdmin)setSelProj(null)}}><Icon name={n.icon} size={18}/> {n.label}</div>)}</div>
      <div style={{padding:"12px 16px",borderTop:"1px solid #E2E8F0",display:"flex",alignItems:"center",gap:10}}><div style={S.avatar}>{isAdmin?"A":(piuUser?.charAt(4)?.toUpperCase()||"P")}</div><div style={{overflow:"hidden"}}><div style={{fontWeight:700,fontSize:12,whiteSpace:"nowrap",overflow:"hidden",textOverflow:"ellipsis"}}>{isAdmin?"GOV-ADMIN":piuName||"GOV-PIU"}</div><span style={{...S.badge(isAdmin?"Completed":"In Progress"),fontSize:9}}>{isAdmin?"Admin":"PIU"}</span></div></div>
      <button style={S.logoutBtn} onClick={()=>{setLoggedIn(false);setPage("dashboard");setSelProj(null)}}>↪ Log out</button>
    </div>
    <div style={S.main}>
      <div style={S.topbar}>
        <div style={{fontSize:14,fontWeight:600,color:"#1E293B"}}>Resilient Tourism Development at Tehri Lake Area</div>
        <div style={{display:"flex",alignItems:"center",gap:12}}>
          {page==="dashboard"&&<select style={{...S.select,minWidth:240}} value={selProj===null?"__all__":selProj} onChange={e=>{const v=e.target.value;setSelProj(v==="__all__"?null:Number(v))}}>
            {isAdmin&&<option value="__all__">All Projects (Overview)</option>}
            {ddProjects.map(p=><option key={p.id} value={p.id}>{p.name}</option>)}
          </select>}
          <div style={{fontSize:12,color:"#94A3B8"}}>{new Date().toLocaleDateString("en-GB",{day:"2-digit",month:"short",year:"numeric"})}</div>
        </div>
      </div>
      <div style={S.content}>{pages[page]}</div>
    </div>
    <Chatbot/>
  </div>)
}
